+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using System.Linq;
+
+namespace ContosoUniversity.Tests;
+
+[TestClass]
+public sealed class PaginatedListTests
+{
+    [TestMethod]
+    public void Constructor_SetsPageIndex()
+    {
+        // Arrange & Act
+        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);
+
+        // Assert
+        Assert.AreEqual(2, list.PageIndex);
+    }
+
+    [TestMethod]
+    public void Constructor_CalculatesTotalPages_Correctly()
+    {
+        // 10 items, 3 per page = ceiling(10/3) = 4
+        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);
+        Assert.AreEqual(4, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void Constructor_TotalPages_WhenExactlyDivisible()
+    {
+        // 9 items, 3 per page = 3
+        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 9, 1, 3);
+        Assert.AreEqual(3, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void Constructor_TotalPages_SinglePage()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1, 2 }, 2, 1, 10);
+        Assert.AreEqual(1, list.TotalPages);
+    }
+
+    [TestMethod]
+    public void Constructor_AddsItemsToList()
+    {
+        // Arrange
+        var items = new List<int> { 10, 20, 30 };
+
+        // Act
+        var list = new PaginatedList<int>(items, 30, 1, 3);
+
+        // Assert
+        Assert.AreEqual(3, list.Count);
+        Assert.AreEqual(10, list[0]);
+        Assert.AreEqual(20, list[1]);
+        Assert.AreEqual(30, list[2]);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 3);
+        Assert.IsFalse(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 3);
+        Assert.IsTrue(list.HasPreviousPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_OnLastPage_ReturnsFalse()
+    {
+        // 10 items, 3 per page = 4 pages. Page 4 is the last.
+        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 4, 3);
+        Assert.IsFalse(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_OnFirstPage_WithMultiplePages_ReturnsTrue()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 3);
+        Assert.IsTrue(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void HasNextPage_OnSinglePage_ReturnsFalse()
+    {
+        var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
+        Assert.IsFalse(list.HasNextPage);
+    }
+
+    [TestMethod]
+    public void Create_ReturnsCorrectPageOfItems()
+    {
+        // Arrange
+        var source = Enumerable.Range(1, 20).AsQueryable();
+
+        // Act
+        var result = PaginatedList<int>.Create(source, 2, 5);
+
+        // Assert
+        Assert.AreEqual(2, result.PageIndex);
+        Assert.AreEqual(4, result.TotalPages); // 20 / 5 = 4
+        Assert.AreEqual(5, result.Count);
+        Assert.AreEqual(6, result[0]); // Items 6-10 on page 2
+        Assert.AreEqual(7, result[1]);
+        Assert.AreEqual(8, result[2]);
+        Assert.AreEqual(9, result[3]);
+        Assert.AreEqual(10, result[4]);
+    }
