using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    private void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
            new Student { FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { FirstMidName = "Yan", LastName = "Li", EnrollmentDate = DateTime.Parse("2012-09-01") }
        );
        context.SaveChanges();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithStudentsOrderedByLastName()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(5, model.Count);
        // Default sort is by LastName ascending
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
    }

    [TestMethod]
    public void Index_SortByNameDesc_ReturnsSortedDescending()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Li", model[0].LastName);
    }

    [TestMethod]
    public void Index_SortByDate_ReturnsSortedByDateAscending()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // Carson Alexander has the earliest date (2010)
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SortByDateDesc_ReturnsSortedByDateDescending()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        // Arturo Anand has the latest date (2013)
        Assert.AreEqual("Anand", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_FiltersResults()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, null, "Al", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count); // Alexander and Alonso
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, null, "Carson", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_WithSearchString_ResetsToPage1()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, null, "Alex", 5) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex); // Reset to page 1
    }

    [TestMethod]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, "Li", null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Li", model[0].LastName);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParms()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("name_desc", controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithNameDescSort_ToggleSortParms()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        controller.Index("name_desc", null, null, null);

        // Assert
        Assert.AreEqual("", controller.ViewBag.NameSortParm);
    }

    [TestMethod]
    public void Index_WithDateSort_ToggleDateParm()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedStudents(context);
        using var controller = new StudentsController(context);

        // Act
        controller.Index("Date", null, null, null);

        // Assert
        Assert.AreEqual("date_desc", controller.ViewBag.DateSortParm);
    }

    // --- Details Tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        var student = new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") };
        context.Students.Add(student);
        context.SaveChanges();
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Details(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model.LastName);
        Assert.AreEqual("Carson", model.FirstMidName);
    }

    // --- Create GET Tests ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST Tests ---

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
