    [TestMethod]
    public void Index_Pagination_ReturnsCorrectPageSize()
    {
        // Arrange - Create 15 students
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        for (int i = 0; i < 15; i++)
        {
            context.Students.Add(new Student
            {
                FirstMidName = $"Student{i}",
                LastName = $"Last{i:D2}",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            });
        }
        context.SaveChanges();
        using var controller = new StudentsController(context);

        // Act - Page size is 10
        var result = controller.Index(null, null, null, 1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(10, model.Count);
        Assert.AreEqual(2, model.TotalPages);
        Assert.IsTrue(model.HasNextPage);
        Assert.IsFalse(model.HasPreviousPage);
    }

    [TestMethod]
    public void Index_Pagination_Page2_ReturnsRemainingItems()
    {
        // Arrange - Create 15 students
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        for (int i = 0; i < 15; i++)
        {
            context.Students.Add(new Student
            {
                FirstMidName = $"Student{i}",
                LastName = $"Last{i:D2}",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            });
        }
        context.SaveChanges();
        using var controller = new StudentsController(context);

        // Act
        var result = controller.Index(null, null, null, 2) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(5, model.Count);
        Assert.IsFalse(model.HasNextPage);
        Assert.IsTrue(model.HasPreviousPage);
    }
}

