        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    private Mock<IWebHostEnvironment> CreateMockEnv()
    {
        var mock = new Mock<IWebHostEnvironment>();
        mock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        mock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        return mock;
    }

    private Mock<ILogger<CoursesController>> CreateMockLogger()
    {
