using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    private void SeedData(SchoolContext context, out Instructor instructor1, out Instructor instructor2, out Course course1, out Course course2)
    {
        var dept = new Department { Name = "Engineering", Budget = 350000, StartDate = DateTime.Parse("2007-09-01") };
        context.Departments.Add(dept);
        context.SaveChanges();

        instructor1 = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        instructor2 = new Instructor
        {
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
        course2 = new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor1.ID, CourseID = course1.CourseID });
        context.SaveChanges();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedData(context, out _, out _, out _, out _);
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedData(context, out var instructor1, out _, out _, out _);
        using var controller = new InstructorsController(context);

        // Act
        var result = controller.Index(instructor1.ID, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count()); // instructor1 has 1 course assignment
    }

    [TestMethod]
    public void Index_WithInstructorAndCourseId_PopulatesEnrollments()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        SeedData(context, out var instructor1, out _, out var course1, out _);

        // Add an enrollment
        var student = new Student { FirstMidName = "Test", LastName = "Student", EnrollmentDate = DateTime.Parse("2023-01-01") };
        context.Students.Add(student);
        context.SaveChanges();
        context.Enrollments.Add(new Enrollment { CourseID = course1.CourseID, StudentID = student.ID, Grade = Grade.A });
        context.SaveChanges();

