            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
        course2 = new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor1.ID, CourseID = course1.CourseID });
