    [TestMethod]
    public void About_ReturnsViewWithEnrollmentStats()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        var date1 = DateTime.Parse("2010-09-01");
        var date2 = DateTime.Parse("2012-09-01");
        context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = date1 },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = date2 },
            new Student { FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = date2 }
        );
        context.SaveChanges();
        using var controller = new HomeController(context);

        // Act
        var result = controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count); // 2 distinct enrollment dates

        var group2012 = model.First(g => g.EnrollmentDate == date2);
        Assert.AreEqual(2, group2012.StudentCount);

        var group2010 = model.First(g => g.EnrollmentDate == date1);
