    [TestMethod]
    public void About_MultipleStudentsSameDate_GroupsCorrectly()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        var date = DateTime.Parse("2023-09-01");
        for (int i = 0; i < 5; i++)
