    private SchoolContext CreateContext(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    [TestInitialize]
    public void DrainStaticQueue()
    {
        // Drain the static notification queue to avoid cross-test contamination
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    [TestMethod]
    public void GetNotifications_NoNotifications_ReturnsEmptyList()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new NotificationsController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        // Result is JsonResult; check the value properties
        var value = result.Value;
        Assert.IsNotNull(value);
        // Use reflection to check dynamic object properties
        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsUpTo10()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new NotificationsController(context);

        // Send 15 notifications through the controller's notification service
        for (int i = 0; i < 15; i++)
        {
            controller.notificationService.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = controller.GetNotifications();

        // Assert
        var value = result.Value;
        Assert.IsNotNull(value);
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value)); // Max 10
    }

    [TestMethod]
    public void GetNotifications_WithFewNotifications_ReturnsAll()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new NotificationsController(context);

        controller.notificationService.SendNotification("Course", "1", "Math", EntityOperation.CREATE);
        controller.notificationService.SendNotification("Course", "2", "Science", EntityOperation.UPDATE);

        // Act
        var result = controller.GetNotifications();

        // Assert
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(2, countProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new NotificationsController(context);

        // Act
        var result = controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
