        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new NotificationsController(context);

        // Act
        var result = controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void GetNotifications_AfterReceiving_QueueIsDrained()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new NotificationsController(context);

        controller.notificationService.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act - first call drains
        controller.GetNotifications();

        // Second call should return 0
        var result = controller.GetNotifications();

        // Assert
        var value = result.Value;
        var countProp = value.GetType().GetProperty("count");
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_ReturnsNotificationDetails()
    {
        // Arrange
        var dbName = Guid.NewGuid().ToString();
        using var context = CreateContext(dbName);
        using var controller = new NotificationsController(context);

        controller.notificationService.SendNotification("Department", "42", "Engineering", EntityOperation.DELETE);

        // Act
        var result = controller.GetNotifications();

        // Assert
        var value = result.Value;
        var successProp = value.GetType().GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));

        var notificationsProp = value.GetType().GetProperty("notifications");
        var notifications = notificationsProp.GetValue(value) as System.Collections.Generic.List<Notification>;
        Assert.IsNotNull(notifications);
        Assert.AreEqual(1, notifications.Count);
        Assert.AreEqual("Department", notifications[0].EntityType);
        Assert.AreEqual("42", notifications[0].EntityId);
        Assert.AreEqual("DELETE", notifications[0].Operation);
        Assert.AreEqual("Department 'Engineering' has been deleted", notifications[0].Message);
    }
}

